code.imports:
import { tags } from 'decantr/tags';
import { css } from 'decantr/css';
import { Button, icon } from 'decantr/components';

code.example:
function JsonViewer({ data, title }) {
  const { div, pre, code, span, button } = tags;
  const json = JSON.stringify(data, null, 2);

  return div({ class: css('_flex _col _r3 _overflow[hidden] _border _bordermuted/20') },
    div({ class: css('_flex _aic _jcsb _px4 _py2 _bgmuted/5 _borderb _bordermuted/20') },
      span({ class: css('_textsm _fontmedium _fgmuted') }, title || 'JSON'),
      div({ class: css('_flex _gap2') },
        Button({ variant: 'ghost', size: 'xs', onclick: () => navigator.clipboard.writeText(json) },
          icon('copy', { size: '0.875rem' }), ' Copy'
        ),
        Button({ variant: 'ghost', size: 'xs' },
          icon('chevrons-down-up', { size: '0.875rem' }), ' Collapse All'
        )
      )
    ),
    pre({ class: css('_p4 _overflow[auto] _bgcanvas _textxs _mono _leading[1.6] _m0') },
      code({}, json)
    )
  );
}

